<?php
namespace App\Domain\Inventory\Capacity;
use App\Domain\Inventory\Capacity\Data\InventoryCapacityResult;
use App\Models\Character;
use Carbon\CarbonImmutable;
use InvalidArgumentException;
final class InventoryCapacityCalculator{public function effective(Character $character,CarbonImmutable $now){$base=(int)$character->base_inventory_slots;if($base<=0||$base>InventoryCapacityLimits::MAX_OPERATIONAL_SLOTS)throw new InvalidArgumentException('Invalid base inventory capacity.');$grants=$character->inventoryCapacityGrants()->where('is_active',true)->where(function($q)use($now){$q->whereNull('starts_at')->orWhere('starts_at','<=',$now);})->where(function($q)use($now){$q->whereNull('ends_at')->orWhere('ends_at','>',$now);})->get();$permanent=0;$temporary=0;foreach($grants as $grant){if($grant->slots<=0)throw new InvalidArgumentException('Invalid capacity grant.');if($grant->ends_at===null)$permanent+=$grant->slots;else$temporary+=$grant->slots;}$effective=$base+$permanent+$temporary;if($effective>InventoryCapacityLimits::MAX_OPERATIONAL_SLOTS)throw new InvalidArgumentException('Effective inventory capacity exceeds operational limit.');return[$effective,$permanent,$temporary];}public function result($effective,$permanent,$temporary,$current,$projected){$reserve=min(InventoryCapacityLimits::PENDING_REWARD_RESERVED_SLOTS,$effective);return new InventoryCapacityResult(['effective_capacity'=>$effective,'permanent_granted_slots'=>$permanent,'temporary_granted_slots'=>$temporary,'current_used_slots'=>$current,'current_free_slots'=>max(0,$effective-$current),'current_capacity_deficit'=>max(0,$current-$effective),'projected_used_slots'=>$projected,'projected_free_slots'=>max(0,$effective-$projected),'effective_reserve'=>$reserve,'claim_fits'=>$projected<=$effective,'hunting_can_continue'=>$projected<=($effective-$reserve),'missing_slots_for_claim'=>max(0,$projected-$effective),'remaining_slots_before_reserve'=>max(0,$effective-$reserve-$projected)]);}}
